[
  {
    "idea": "Analyze the average alcohol consumption per state to identify market opportunities for alcohol and beverage stocks",
    "data": {
      "source": "National Survey on Drug Use and Health (NSDUH)",
      "type": "api",
      "frequency": "annual",
      "stable": true
    },
    "behavior": "Differences in average alcohol consumption across states can reveal potential growth markets for alcohol and beverage companies.",
    "market_impact": {
      "direction": "bullish",
      "sector": "XLY",
      "rationale": "Higher alcohol consumption in a state could indicate stronger demand for consumer discretionary products like alcohol and beverages."
    },
    "trade_logic": {
      "entry": "When a state's average alcohol consumption is 10% above the national average for two consecutive years",
      "exit": "After 6 months or if the state's consumption falls back to the national average",
      "expected_frequency": "medium"
    }
  }
]
